class DSU {
    parent: number[];
    constructor(n: number) {
        this.parent = new Array(n).fill(0).map((_, i) => i);
    }
    find(x: number): number {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }
    union(x: number, y: number): void {
        const fx = this.find(x);
        const fy = this.find(y);
        if (fx !== fy) {
            this.parent[fx] = fy;
        }
    }
}

function solve(n: number, edges: number[][], k: number): number {
    let maxEdge = 0;
    for (const e of edges) {
        if (e[2] > maxEdge) {
            maxEdge = e[2];
        }
    }
    let low = 0, high = maxEdge;
    let answer = maxEdge;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const dsu = new DSU(n);
        for (const e of edges) {
            if (e[2] <= mid) {
                dsu.union(e[0], e[1]);
            }
        }
        let components = 0;
        for (let i = 0; i < n; i++) {
            if (dsu.find(i) === i) {
                components++;
            }
        }
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
```

